#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    int count = 0;
    for (int i = 1; i <= n; ++i) {
        int sum = 0;
        int temp = i;
        while (temp > 0) {
            if (temp % 2 == 0) {
                sum += 1;
            } else { 
                sum += 2;
            }
            temp = temp / 2;
        }
        if (sum % 2 != 0) {
            count++;
        }
    }
    cout << count << endl;
    return 0;
}

