code.C:
#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);

    int count = 0;
    for (int i = 1; i <= n; i++) {
        int sum = 0;
        int temp = i;
        while (temp > 0) {
            if (temp % 2 == 0) {
                sum += 1;
            } else {
                sum += 2;
            }
            temp /= 2;
        }
        if (sum % 2 != 0) {
            count++;
        }
    }

    printf("%d\n", count);
    return 0;
}

